import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        int bufferSize = Math.min(userInput.length(), 10); // Determine actual buffer size

        char[] buffer = new char[bufferSize];

        userInput.getChars(0, bufferSize, buffer, 0); // Copy limited user input to buffer

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

